// Extract key themes from transcript
const transcript = $input.first().json.text;
const contactName = $('Webhook - Receive Audio').first().json.body.contactName;
const contactEmail = $('Webhook - Receive Audio').first().json.body.contactEmail;
const company = $('Webhook - Receive Audio').first().json.body.company;
const notes = $('Webhook - Receive Audio').first().json.body.notes || '';

// Theme detection keywords
const themes = {
  'fraud_prevention': ['fraud', 'fraudulent', 'chargeback', 'dispute', 'risk', 'detection'],
  'compliance': ['compliance', 'regulatory', 'regulation', 'audit', 'gdpr', 'sox', 'pci'],
  'cost_optimization': ['cost', 'expense', 'budget', 'savings', 'efficiency', 'reduce'],
  'digital_transformation': ['digital', 'transformation', 'modernize', 'cloud', 'automation'],
  'general': []
};

let detectedTheme = 'general';
let maxMatches = 0;

for (const [theme, keywords] of Object.entries(themes)) {
  const matches = keywords.filter(kw => 
    transcript.toLowerCase().includes(kw) || notes.toLowerCase().includes(kw)
  ).length;

  if (matches > maxMatches) {
    maxMatches = matches;
    detectedTheme = theme;
  }
}

// Map theme to white paper URL (update these URLs with your actual white papers)
const whitePapers = {
  'fraud_prevention': 'https://your-replit-url.replit.app/whitepapers/fraud-prevention.pdf',
  'compliance': 'https://your-replit-url.replit.app/whitepapers/compliance-guide.pdf',
  'cost_optimization': 'https://your-replit-url.replit.app/whitepapers/cost-optimization.pdf',
  'digital_transformation': 'https://your-replit-url.replit.app/whitepapers/digital-transformation.pdf',
  'general': 'https://your-replit-url.replit.app/whitepapers/company-overview.pdf'
};

const whitePaperUrl = whitePapers[detectedTheme];

return {
  transcript,
  contactName,
  contactEmail,
  company,
  theme: detectedTheme,
  whitePaperUrl,
  activityId: $('Webhook - Receive Audio').first().json.body.activityId,
  callbackUrl: $('Webhook - Receive Audio').first().json.body.callbackUrl
};

// Map theme to Outreach sequence ID
// You must create these sequences in Outreach.io first and replace with actual IDs
const sequenceMapping = {
  'fraud_prevention': 123,  // Replace with your Fraud Prevention sequence ID
  'compliance': 124,        // Replace with your Compliance sequence ID
  'cost_optimization': 125, // Replace with your Cost Optimization sequence ID
  'digital_transformation': 126, // Replace with your Digital Transformation sequence ID
  'general': 127            // Replace with your General Follow-up sequence ID
};

const theme = $('Extract Theme & Map White Paper').first().json.theme;
const prospectId = $input.first().json.data.id;

return {
  prospectId,
  sequenceId: sequenceMapping[theme] || sequenceMapping['general'],
  theme
};
